sql:
SELECT export_id, report_id, format_id, export_date
FROM report_exports
WHERE export_date = '2022-01-01';

SELECT report_id, report_date, report_details
FROM sales_reports
WHERE report_format = 'PDF';

SELECT executive_name
FROM sales_executives
WHERE commission_rate > (SELECT AVG(commission_rate) FROM sales_executives);

external_knowledge:
- "Highest sales" refers to the cities with the largest total sales amounts; 
- "Sales performance ranking" is determined by the rank and percent rank based on the total sales amount;
- "Product types" are categories such as coin, bar, jewelry, etc.

sql:
SELECT analyst_name
FROM analysts
WHERE analyst_id = 1;

SELECT se.executive_name
FROM sales_executives se
WHERE se.executive_id IN (SELECT u.user_id FROM users u);

SELECT * 
FROM sales_executives 
WHERE commission_rate < (SELECT AVG(commission_rate) FROM sales_executives);

SELECT payment_method
FROM customer_payments
WHERE payment_amount > 50000;
